const ev = $json;
const p = ev.payload || {};
const parts = [
  'price action',
  p.action || p.direction || '',
  p.strategy || p.alert_name || '',
  ev.instrument || p.ticker || '',
  p.timeframe || p.interval || '',
  p.price ? 'price ' + p.price : '',
  p.sl ? 'stop ' + p.sl : '',
  p.tp ? 'target ' + p.tp : ''
];
const q = parts.filter(Boolean).join(' ').trim();
const sym = (ev.instrument || p.ticker || '').toUpperCase();
const isCrypto = /USDT$|USDC$|BUSD$/.test(sym);
const priceUrl = isCrypto
  ? 'https://api.bybit.com/v5/market/tickers?category=spot&symbol=' + sym
  : 'https://query1.finance.yahoo.com/v8/finance/chart/' + encodeURIComponent(sym) + '?interval=1m&range=1d';
return { json: { ...ev, rag_query: q.slice(0, 500), _price_url: priceUrl, _price_source_type: isCrypto ? 'bybit' : 'yahoo' } };

parameters.query:
SELECT event_id, event_instrument, event_payload, book_slug, chunk_idx, title, content, score FROM (
                    SELECT '{{ $('Merge Price').first().json.event_id }}'::uuid AS event_id,
                           '{{ $('Merge Price').first().json.instrument || '' }}' AS event_instrument,
                           '{{ JSON.stringify($('Merge Price').first().json.payload) }}'::jsonb AS event_payload
                ) ev
                CROSS JOIN LATERAL search_knowledge(('[' || '{{ $json.embedding.values.join(',') }}' || ']')::vector, 3);

parameters.jsCode:
const event = $('Merge Price').first().json;
const chunks = items.map(i => i.json).filter(c => c.content);

const contextBlocks = chunks.slice(0, 3).map((c, i) =>
  `[${i + 1}] ${c.book_slug}/${c.chunk_idx} (score=${Number(c.score).toFixed(2)})\n${c.content}`
).join('\n\n---\n\n');

const systemPrompt = `You are TechnicalAgent, a specialist trading analyst focused on price action + market structure. Input: a technical event (TradingView alert or price pattern trigger). Output: ONE structured trade signal JSON — or {"skip": true, "reason": "..."} if no actionable setup.

MANDATORY CHECKS (in order):
1. If payload.price_source == "payload" AND payload.live_price is null → skip with reason "no live price source for " + instrument
2. If payload.live_price exists AND |payload.price_delta_pct| > 2 → skip with reason "stale event: payload price " + payload.payload_price + " differs from live " + payload.live_price + " by " + payload.price_delta_pct + "%"
3. Otherwise use payload.live_price as the authoritative current price for entry/SL/TP reasoning

Apply in order of priority:
- Wyckoff phases: identify accumulation / distribution / markup / markdown — label current phase and key event (spring, upthrust, SOS, SOW)
- Elder triple screen: HTF trend → MTF oscillator → LTF entry
- Al Brooks price action: trend bar, pullback depth, breakout quality
- Van Tharp R-multiple: stop >= 1R beyond structure, target >= 2R
- Taleb convexity: reject capped upside + open downside

Signal schema — return ONLY this JSON:
{
  "instrument": "string",
  "timeframe": "15m|1H|4H|1D|...",
  "bias": "long|short|flat",
  "confidence": 0.0-1.0,
  "entry": number|null,
  "sl": number|null,
  "tp": [number]|null,
  "r_multiple": number|null,
  "rationale": "one sentence: phase + trigger + structure + live_price reference",
  "knowledge_refs": ["book_slug/chunk_idx", ...],
  "strategy_tag": "wyckoff-spring|elder-triple|brooks-trend-pullback|..."
}
Or: {"skip": true, "reason": "no setup" | "stale event..." | "no live price..."}`;

const userPrompt = `TECHNICAL EVENT
source: ${event.source}
instrument: ${event.instrument || 'n/a'}
payload: ${JSON.stringify(event.payload)}

RETRIEVED KNOWLEDGE
${contextBlocks}

Output the signal JSON now.`;

return [{
  json: {
    event_id: event.event_id,
    event_instrument: event.instrument,
    event_payload: event.payload,
    systemPrompt,
    userPrompt,
    knowledge_refs: chunks.slice(0, 3).map(c => `${c.book_slug}/${c.chunk_idx}`)
  }
}];

const ctx = $('Build Gemini Prompt').first().json;
const resp = items[0].json;
return [{ json: { ...resp, event_id: ctx.event_id, event_payload: ctx.event_payload, knowledge_refs: ctx.knowledge_refs } }];

const resp = items[0].json;
let text = '';
try { text = resp.candidates[0].content.parts[0].text; }
catch (e) { return [{ json: { skip: true, reason: 'no candidates', event_id: resp.event_id } }]; }

text = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();

let signal;
try { signal = JSON.parse(text); }
catch (e) { return [{ json: { skip: true, reason: 'parse fail: ' + text.slice(0,100), event_id: resp.event_id } }]; }

if (signal.skip) {
  return [{ json: { skip: true, reason: signal.reason, event_id: resp.event_id } }];
}

const required = ['instrument', 'timeframe', 'bias', 'confidence'];
for (const k of required) {
  if (!(k in signal)) return [{ json: { skip: true, reason: 'missing ' + k, event_id: resp.event_id } }];
}

const effective_refs = (signal.knowledge_refs && signal.knowledge_refs.length ? signal.knowledge_refs : (resp.knowledge_refs || []));


return [{
    json: {
      skip: false,
    event_id: resp.event_id,
    instrument: signal.instrument,
    timeframe: signal.timeframe,
    bias: signal.bias,
    confidence: Number(signal.confidence),
    entry: signal.entry ?? null,
    sl: signal.sl ?? null,
    tp: signal.tp || null,
    r_multiple: signal.r_multiple ?? null,
    rationale: { technical: signal.rationale || '' },
    knowledge_refs: effective_refs,
    strategy_tag: signal.strategy_tag || 'technical',
    telegram_text: `[TECH] ${signal.bias === 'long' ? 'LONG' : signal.bias === 'short' ? 'SHORT' : 'FLAT'} ${signal.instrument} ${signal.timeframe}
confidence: ${Number(signal.confidence).toFixed(2)}
entry: ${signal.entry ?? '-'} sl: ${signal.sl ?? '-'} tp: ${JSON.stringify(signal.tp) || '-'}
why: ${signal.rationale || ''}
refs: ${effective_refs.join(', ')}`
  }
}];

parameters.query:
UPDATE events SET status='processed', processed_at=now(),
                       error='skipped: {{ $json.reason.replace(/'/g, "''") }}'
                WHERE id='{{ $json.event_id }}';

parameters.jsCode:
const rag = $('Build RAG query').first().json;
const resp = items[0].json;
const sourceType = rag._price_source_type;

let livePrice = null, priceSource = 'payload';
try {
  if (sourceType === 'bybit' && resp?.result?.list?.[0]?.lastPrice) {
    livePrice = parseFloat(resp.result.list[0].lastPrice);
    priceSource = 'bybit';
  } else if (sourceType === 'yahoo') {
    const meta = resp?.chart?.result?.[0]?.meta;
    livePrice = meta?.regularMarketPrice ?? null;
    priceSource = livePrice != null ? 'yahoo' : 'payload';
  }
} catch (e) {}

const payloadPrice = parseFloat(rag.payload?.price ?? rag.payload?.close ?? 0) || null;
let priceDeltaPct = null;
if (livePrice != null && payloadPrice != null && payloadPrice > 0) {
  priceDeltaPct = ((payloadPrice - livePrice) / livePrice) * 100;
}

const enrichedPayload = {
  ...(rag.payload || {}),
  live_price: livePrice,
  payload_price: payloadPrice,
  price_delta_pct: priceDeltaPct,
  price_source: priceSource
};

return [{
  json: {
    event_id: rag.event_id,
    ts: rag.ts,
    source: rag.source,
    instrument: rag.instrument,
    payload: enrichedPayload,
    rag_query: rag.rag_query
  }
}];

